### Node.js Server Integration with Transformers.js and Express

Source: https://context7.com/huggingface/transformers.js/llms.txt

This snippet illustrates how to deploy Hugging Face Transformers.js models as HTTP API endpoints using Node.js and the Express framework. It preloads the model on server startup to ensure efficient handling of incoming requests. The implementation uses a singleton pattern for the pipeline to reuse the loaded model across multiple requests, improving performance. Error handling is included for invalid requests or internal processing errors.

```javascript
import http from 'http';
import querystring from 'querystring';
import url from 'url';
import { pipeline } from '@huggingface/transformers';

// Singleton pipeline (loaded once, reused for all requests)
class ClassificationPipeline {
    static task = 'text-classification';
    static model = 'Xenova/distilbert-base-uncased-finetuned-sst-2-english';
    static instance = null;

    static async getInstance(progress_callback = null) {
        if (this.instance === null) {
            console.log('Loading model...');
            this.instance = await pipeline(this.task, this.model, {
                progress_callback
            });
            console.log('Model loaded!');
        }
        return this.instance;
    }
}

// Preload model on server start
ClassificationPipeline.getInstance();

// Create HTTP server
const server = http.createServer();
const hostname = '127.0.0.1';
const port = 3000;

server.on('request', async (req, res) => {
    const parsedUrl = url.parse(req.url);
    const { text } = querystring.parse(parsedUrl.query);

    if (parsedUrl.pathname === '/classify' && text) {
        try {
            // Get classifier instance
            const classifier = await ClassificationPipeline.getInstance();

            // Run classification
            const result = await classifier(text);

            // Send response
            res.setHeader('Content-Type', 'application/json');
            res.end(JSON.stringify(result));
        } catch (error) {
            res.statusCode = 500;
            res.end(JSON.stringify({ error: error.message }));
        }
    } else {
        res.statusCode = 400;
        res.end(JSON.stringify({ error: 'Invalid request' }));
    }
});

server.listen(port, hostname, () => {
    console.log(`Server running at http://${hostname}:${port}/`);
    console.log('Example: http://127.0.0.1:3000/classify?text=I%20love%20transformers');
});

```

